param([Parameter(Mandatory=$true)][string]$CertificateThumbprint,[string]$TimestampUrl='http://timestamp.digicert.com')
$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$targets=@((Join-Path $root 'artifacts\publish\CoreWatch-win-x64\CoreWatch.exe'),(Join-Path $root 'artifacts\CoreWatch-Setup.exe'));$certificate=Get-ChildItem -LiteralPath "Cert:\CurrentUser\My\$CertificateThumbprint";foreach($target in $targets){if(-not(Test-Path -LiteralPath $target)){throw "서명 대상 누락: $target"};$signature=Set-AuthenticodeSignature -LiteralPath $target -Certificate $certificate -TimestampServer $TimestampUrl -HashAlgorithm SHA256;if($signature.Status -ne 'Valid'){throw "서명 실패: $target ($($signature.StatusMessage))"}};Get-AuthenticodeSignature -LiteralPath $targets|Select-Object Path,Status,SignerCertificate
